SELECT p.id, p.name, p."tenantId", t.slug as tenant_slug, b.name as branch_name FROM printers p LEFT JOIN tenants t ON t.id = p."tenantId" LEFT JOIN branches b ON b.id = p.branch_id ORDER BY t.slug; SELECT pa.id, pa.name, pa."tenantId", t.slug as agent_tenant, pa.branch_id, b.name as branch_name, b."tenantId" as branch_tenantId FROM print_agents pa LEFT JOIN tenants t ON t.id = pa."tenantId" LEFT JOIN branches b ON b.id = pa.branch_id ORDER BY t.slug;
